const DatabaseTableOutputOptions = @import("database_table_output_options.zig").DatabaseTableOutputOptions;
const S3TableOutputOptions = @import("s3_table_output_options.zig").S3TableOutputOptions;

/// Represents options that specify how and where in the Glue Data Catalog
/// DataBrew
/// writes the output generated by recipe jobs.
pub const DataCatalogOutput = struct {
    /// The unique identifier of the Amazon Web Services account that holds the Data
    /// Catalog that
    /// stores the data.
    catalog_id: ?[]const u8 = null,

    /// The name of a database in the Data Catalog.
    database_name: []const u8,

    /// Represents options that specify how and where DataBrew writes the database
    /// output
    /// generated by recipe jobs.
    database_options: ?DatabaseTableOutputOptions = null,

    /// A value that, if true, means that any data in the location specified for
    /// output
    /// is overwritten with new output. Not supported with DatabaseOptions.
    overwrite: bool = false,

    /// Represents options that specify how and where DataBrew writes the Amazon S3
    /// output generated by recipe jobs.
    s3_options: ?S3TableOutputOptions = null,

    /// The name of a table in the Data Catalog.
    table_name: []const u8,

    pub const json_field_names = .{
        .catalog_id = "CatalogId",
        .database_name = "DatabaseName",
        .database_options = "DatabaseOptions",
        .overwrite = "Overwrite",
        .s3_options = "S3Options",
        .table_name = "TableName",
    };
};
